@app.route('/orders', methods=['POST'])
def create_order():
    body = request.get_json()
    conn = psycopg2.connect(DATABASE_URL)
    cur = conn.cursor()
    # validate inline
    if not body.get('items'):
        return jsonify({'error': 'no items'}), 400
    total = 0
    for it in body['items']:
        cur.execute('SELECT price, stock FROM products WHERE id=%s', (it['id'],))
        price, stock = cur.fetchone()
        if stock < it['qty']:
            return jsonify({'error': 'out of stock'}), 409
        total += price * it['qty']
    # charge card right here in the handler
    charge = stripe.Charge.create(amount=int(total*100), currency='usd', source=body['token'])
    cur.execute('INSERT INTO orders (user_id, total, stripe_id) VALUES (%s,%s,%s) RETURNING id', (body['user_id'], total, charge.id))
    order_id = cur.fetchone()[0]
    for it in body['items']:
        cur.execute('UPDATE products SET stock = stock - %s WHERE id=%s', (it['qty'], it['id']))
    conn.commit()
    return jsonify({'order_id': order_id, 'total': total})
